<template>
  <div class="mobile-menu d-flex align-items-center justify-content-between">
    <div class="mobile-item" @click="toggleSidebar">
      <img src="../assets/main/menu-mobile.png" />
      <span>Меню</span>
    </div>
    <div class="mobile-item">
      <img src="../assets/main/bonus-menu.png" />
      <span>Бонусы</span>
    </div>
    <div class="mobile-item">
      <img src="../assets/main/games-menu.png" />
      <span>Игры</span>
    </div>
    <div class="mobile-item">
      <img src="../assets/main/pools.png" />
      <span>Ставки</span>
    </div>
    <div class="mobile-item profile" @click="toggleAccount" v-if="isAuthenticated">
      <img src="../assets/main/profile.png" />
      <span>Профиль</span>
    </div>
  </div>
</template>

<script>
export default {
  name: 'MobileHeader',
  props: {
    collapsed: {
      type: Boolean,
      default: false
    },
    isAuthenticated: {
      type: Boolean,
      required: true
    },
    expandedAccount: {
      type: Boolean,
      default: false
    }
  },
  methods: {
    toggleSidebar() {
      this.$emit('toggle-sidebar', !this.collapsed);
    },
    toggleAccount() {
      this.$emit('toggle-account', !this.expandedAccount);
    },
    showProfile() {
      this.$emit('show-profile');
    }
  }
}
</script>
    
<style lang="scss" scoped>
.mobile-menu {
    position: fixed;
    width: 90%;
    background: #1A1B1D;
    padding: 5px 25px;
    border-radius: 50px;
    bottom: 15px;
    border: 1px solid #232426;
}
.mobile-item img, .mobile-item span{
    text-align: center;
    display: block;
}
.mobile-item img {
    margin: 0px auto;
    border-radius: 50%;
    padding: 10px 10px;
}
.mobile-item:hover img , .mobile-item:focus img , .mobile-item:active img  {
  background: #FDF74B;
}
.mobile-item.profile img  {
    margin: 0 auto;
    padding: 0;
}
.mobile-item span {
    font-family: "Strapel bold";
    color: #717171;
    font-size: 11px;
    text-align: center;
    margin-top:5px;
}
</style>