              <div class="d-flex align-items-center">
                <img src="../assets/main/dollar.png" />
                <span>USD</span>
              </div>
              <p>$1 283.93208</p>
            </div>
            <div class="details-item d-flex justify-content-between align-items-center">
              <div class="d-flex align-items-center">
                <img src="../assets/main/wincoin.png" />
                <span>WinCoin</span>
              </div>
              <p>21.93 шт</p>
            </div>
            <div class="details-item d-flex justify-content-between align-items-center">
              <div class="d-flex align-items-center">
                <img src="../assets/main/fg.png" />
                <span>FreeGame</span>
              </div>
