                </a>
                <a class="d-flex align-items-center">
                  <img src="../assets/main/menu-transactions.png" />
                  История транзакций
                </a>
                <a class="d-flex align-items-center">
                  <img src="../assets/main/menu-history.png" />
                  История игр
                </a>
              </div>
              <div class="d-flex align-items-center justify-content-center mt-3 mb-3">
                <button class="logout" @click="logout"><img src="../assets/main/account-exit.png" />Выход</button>
              </div>
            </div>
          </transition>
        </div>

        <div class="related-buttons">
          <button v-if="!isMobile" class="language ms-3 me-3" @click="toggleLanguage"><img
              src="../assets/main/rus-lang.png" /></button>
          <button v-if="!isMobile" class="settings me-3" @click="toggleSettings"><img
              src="../assets/main/settings.png" /></button>
          <button v-if="!isMobile" class="notifications me-3"><img src="../assets/main/notfications.png" /></button>
          <button v-if="!isMobile" class="chat me-3"><img src="../assets/main/chat.png" /></button>
          <button v-if="!isMobile" class="menu-collapse"><i class="fa-solid fa-caret-up"></i></button>

          <!-- язык -->
          <transition name="fade">
            <div class="wallet-details" v-if="expandedLanguage">
              <div class="details-item active d-flex align-items-center">
                <img src="../assets/main/ruslang.png" />
                <span>Русский</span>
              </div>
              <div class="details-item d-flex align-items-center">
                <img src="../assets/main/englang.png" />
                <span>English</span>
              </div>
              <div class="details-item d-flex align-items-center">
                <img src="../assets/main/gerlang.png" />
                <span>German</span>
              </div>
            </div>
          </transition>

          <!-- Настройки -->
          <transition name="fade">
            <div class="wallet-details settings" v-if="expandedSettings">
              <div class="sound-container">
                <div class="d-flex justify-content-between align-items-center mb-4">
                  <div class="d-flex align-items-center">
                    <img class="me-2" src="../assets/main/sound.png" />
                    <p class="font-bold">Все звуки</p>
                  </div>

                  <div class="toggle-switch" @click="toggleSwitch">
                    <div class="toggle-switch-inner" :class="{ 'toggle-switch-on': isOn }">
                      <div class="toggle-switch-knob"></div>
                    </div>
                  </div>
                </div>

                <p class="font-grey">Музыка</p>
                <div class="volume-slider-container mt-2 mb-3">
                  <VolumeSlider v-model="volume" />
                </div>
                <p class="font-grey">Эффекты</p>
                <div class="volume-slider-container mt-2 mb-3">
                  <VolumeSlider v-model="volume" />
                </div>
              </div>
              <div class="details-item d-flex justify-content-between align-items-center">
                <div class="d-flex align-items-center">
                  <img src="../assets/main/round-dollar.png" />
                  <div class="ms-2">
                    <p class="font-grey">отображать в фиате</p>
                    <span class="ms-0">USD</span>
                  </div>
                </div>
                <button class="toggle-sidebar settings">
                  <i class="fa-solid fa-caret-down"></i>
                </button>
              </div>
              <div class="details-item d-flex justify-content-between align-items-center">
                <div class="d-flex align-items-center">
                  <img src="../assets/main/round-dollar.png" />
                  <div class="ms-2">
                    <p class="font-grey">Валюта для спорта</p>
                    <span class="ms-0">USD</span>
                  </div>
                </div>
                <button class="toggle-sidebar">
                  <i class="fa-solid fa-caret-down"></i>
                </button>
              </div>
              <div class="bottom-menu p-1 mt-2">
                <div class="d-flex justify-content-between align-items-center mb-2">
                  <div class="d-flex align-items-center">
                    <img class="me-2" src="../assets/main/hide.png" />
                    <p class="font-grey">Скрыть<br>заблокированные игры</p>
                  </div>

                  <div class="toggle-switch" @click="toggleSwitch">
                    <div class="toggle-switch-inner" :class="{ 'toggle-switch-on': isOn }">
                      <div class="toggle-switch-knob"></div>
                    </div>
                  </div>
                </div>
                <div class="d-flex justify-content-between align-items-center">
                  <div class="d-flex align-items-center">
                    <img class="me-2" src="../assets/main/animation.png" />
                    <p class="font-grey">Анимация</p>
                  </div>

                  <div class="toggle-switch" @click="toggleSwitch">
                    <div class="toggle-switch-inner" :class="{ 'toggle-switch-on': isOn }">
                      <div class="toggle-switch-knob"></div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </transition>

        </div>

      </div>

    </div>
    <!-- TEMPORARY FOR MOBILES аккаунт -->
    <transition name="fade" class="account" v-if="isMobile">
      <div class="account-details" v-if="expandedAccount">
        <img src="../assets/main/big-account.png" />
        <div class="d-flex align-items-bottom justify-content-between">
          <span class="level">Level 9</span>
          <span class="score">$326/$705</span>
        </div>
        <div class="progress-bar-container">
          <div class="progress-bar"></div>
        </div>
        <div class="menu">
          <a class="d-flex align-items-center">
            <img src="../assets/main/menu-account.png" />
            Аккаунт
          </a>
          <a class="d-flex align-items-center">
            <img src="../assets/main/menu-transactions.png" />
            История транзакций
          </a>
          <a class="d-flex align-items-center">
            <img src="../assets/main/menu-history.png" />
            История игр
          </a>
        </div>
        <div class="d-flex align-items-center justify-content-center mt-3 mb-3">
          <button class="logout" @click="logout"><img src="../assets/main/account-exit.png" />Выход</button>
        </div>
      </div>
    </transition>

  </header>

</template>

<script>
import VolumeSlider from './VolumeSlider.vue'; // Импорт компонента ползунка громкости


export default {
  name: 'HeaderComponent',
  components: {
    VolumeSlider,

  },
  props: {
    isAuthenticated: {
      type: Boolean,
      required: true
    },
    expandedAccount: {
      type: Boolean,
      default: false
    }
  },
  inject: ['isMobile'],
  data() {
    return {
      isOn: false,
      isSidebarCollapsed: false,
      expandedMoney: false,
      expandedLanguage: false,
      expandedSettings: false,
      volume: 50, // Начальная громкость
    };
  },
  methods: {
    toggleSidebar() {
      this.isSidebarCollapsed = !this.isSidebarCollapsed;
      this.$emit('toggle-sidebar', this.isSidebarCollapsed);
    },
    login() {
      this.$emit('login');
    },
    logout() {
      this.$emit('logout');
    },
    toggleSwitch() {
      this.isOn = !this.isOn;
      this.$emit('change', this.isOn); // Emit an event when the state changes
    },
    toggleMoney() {
      this.expandedMoney = !this.expandedMoney;
    },
    toggleAccount() {
      this.$emit('toggle-account', !this.expandedAccount);
    },
    toggleLanguage() {
      this.expandedLanguage = !this.expandedLanguage;
    },
    toggleSettings() {
      this.expandedSettings = !this.expandedSettings;
    }
  }
}
</script>

<style lang="scss" scoped>
.header {
  background-color: $bg-secondary-color;
  padding: 17px;
  border-bottom: 1px solid #191A1C;

  button {
    background: $bg-element-color;
    outline: none;
    border: none;
    color: #3B3C3E;
    padding: 14px 15px;
    border-radius: 10px;

    &:hover {
      background-color: $bg-element-color-light;
      transform: scale(0.98);
    }

    &:active {
      background-color: $bg-element-color-darker;
      transform: scale(0.98);
    }
  }

  button.toggle-sidebar,
  button.menu-collapse {
    padding: 15px 23px;
  }

  .logo {
    margin-right: 120px;

    .default-logo {
      display: block;
    }

    .hover-logo {
      display: none;
      height: 53px;
      width: auto;
    }

    &:hover {
      .default-logo {
        display: none;
      }

      .hover-logo {
        display: block;
      }
    }
  }

  .bonus {
    background: $bg-violet-color;
    border-radius: 10px;
    color: #101010;
    font-family: "Strapel bold";

    &:hover {
      background-color: $bg-violet-light;
      transform: scale(0.98);
    }

    &:active {
      background-color: $bg-violet-darker;
      transform: scale(0.98);
    }
  }

  .wallet {
    background-color: $bg-element-color;
    border-radius: 10px;
    padding: 7px 15px;
    position: relative;
    cursor: pointer;

    .fa-dollar-sign {
      background: $bg-blue;
      border-radius: 50%;
      font-weight: 700;
      font-size: 20px;
      color: #1B1C1E;
      padding: 4px 8px;
    }

    p {
      font-family: "Strapel medium";
      margin-bottom: 0;
      color: #AFB0B2;
    }

    .fa-caret-down {
      transition: transform 0.3s ease;
      cursor: pointer;
    }

    .fa-caret-up {
      transform: rotate(180deg);
      cursor: pointer;
    }
  }

  .wallet-details {
    background-color: $bg-secondary-color;
    border-radius: 10px;
    border: 1px solid $bg-secondary-color;
    padding: 15px;
    margin-top: 10px;
    color: #333;
    transition: max-height 0.3s ease;
    position: absolute;
    top: 80px;
    left: 0;
    z-index: 2;

    .details-item {
      border-radius: 10px;
      background: $bg-third-color;
      padding: 12px 20px;
      margin-bottom: 10px;
      width: 300px;

      span {
        font-family: "Strapel bold";
        color: #D4D4D4;
        font-size: 16px;
        margin-left: 10px;
      }

      p {
        font-family: "Strapel medium";
        margin-bottom: 0;
        color: #AFB0B2;
      }
    }

    .details-item.active {
      background: $bg-element-color;
      border: 1px solid #242527;
    }
  }

  .wallet-details.settings {
    left: unset;
    z-index: 2;
    right: 50%;
  }

  .add_wallet {
    background: $bg-blue;
    border-radius: 8px;
    font-size: 24px;
    color: #1B1C1E;
    padding: 2px 9px;

  }

  button.login {
    color: #A8A9AB;
    font-family: "Strapel bold";
    text-transform: uppercase;
  }

  button.register {
    background: $bg-yellow;
    font-family: "Strapel bold";
    text-transform: uppercase;
  }

  .related-buttons {
    position: relative;

    .menu-collapse {
