  }

  .header .wallet-details[data-v-61dd7a3d] {
    left: unset;
    right: 0;
  }
  .header .account-details {
    position: fixed;
    top: unset;
    width: 75%;
    margin: 0 auto;
    bottom: 100px;
    left:0;
  }
}
</style>
